private void processOptionToken(String token, boolean stopAtNonOption)
{
    if (token.startsWith("-")) 
    {
        // Ignore unrecognized long options, which start with "-" but do not exist in options definition
        if (!options.hasLongOpt(token.substring(1)))
        {
            throw new UnrecognizedOptionException(token);
        }

        String optName=null;
        // When user provides "-longOption arg", it should be splitted into two tokens "-longOption" & "arg".
        for(Iterator iterator=options.iterator();iterator.hasNext();){
            CommandLineOption cliopt=(CommandLineOption)iterator.next();
            List<String> names=cliopt.getNames();

            for(int i=0;names!= null && i < names.size() ;i++){
                if(!names.get(i).equalsIgnoreCase(token)){
                    continue;
                }    

                // If no argument expected for this option then add it to tokens list and return from here
                if((currentOption==null || !currentOption.isArgsAllowed())&&currentArg==null){
                     currentOption = cliopt;
                     tokens.add(token);


                     return;
                }

                 optName=names.get(i);
            }

        }

      if(currentOption ==null )
       {
           currentOption =new DefaultCommadlineOptionDecorator(new org.apache.commons.cli.Option(optName,null));

       }
        tokens.add(token);  
    }

    else
    {
        if (!stopAtNonOption)
        {
            if (currentOption == null)
            {
                throw new ParseException("Missing option");
            }
            currentOption.setArgument(token);
        }
        else
        {
            tokens.add(token);
        }
    }
}

